//! speed_of_light — the **%c** runtime metric, carried with Lean proof across monster / uring /
//! wasm-simd. A runtime's speed as a percentage of the information lightcone front (`c`):
//!
//!     cPercent = transmit / (transmit + compute) * 100
//!
//! A CACHE HIT pays zero compute — pure transmission — so it rides the front at 100% c (the photon:
//! `Gnosis.RuntimeSpeedOfLightPercent.cache_hit_is_luminal`). A RECOMPUTE pays compute on top of
//! transmission, so it is strictly subluminal (`...recompute_is_subluminal`) — the pursuer of the
//! Ackermann lightcone co-theorem. Aggregated over a workload, **%c = the cache hit rate**: each hit
//! is a photon, each miss recomputes. More cache warmth = higher %c = closer to the speed of light.

/// Lean theorem IDs backing the %c metric — carried verbatim by every report.
pub const CACHE_HIT_IS_LUMINAL_THEOREM_ID: &str =
    "Gnosis.RuntimeSpeedOfLightPercent.cache_hit_is_luminal";
pub const RECOMPUTE_IS_SUBLUMINAL_THEOREM_ID: &str =
    "Gnosis.RuntimeSpeedOfLightPercent.recompute_is_subluminal";
pub const LESS_COMPUTE_MORE_C_THEOREM_ID: &str =
    "Gnosis.RuntimeSpeedOfLightPercent.less_compute_more_c";
pub const PERCENT_C_RIDES_FRONT_THEOREM_ID: &str =
    "AckermannIsLightSpeed.runtime_percent_c_rides_the_front";

pub const PERCENT_C_THEOREM_IDS: [&str; 4] = [
    CACHE_HIT_IS_LUMINAL_THEOREM_ID,
    RECOMPUTE_IS_SUBLUMINAL_THEOREM_ID,
    LESS_COMPUTE_MORE_C_THEOREM_ID,
    PERCENT_C_RIDES_FRONT_THEOREM_ID,
];

/// %c of a single delivery: the share that is the irreducible causal transmission floor, vs. the
/// avoidable compute. `transmit + compute == 0` ⇒ 0. A cache hit (`compute == 0`) ⇒ 100.
pub fn c_percent(transmit: f64, compute: f64) -> f64 {
    let denom = transmit + compute;
    if denom <= 0.0 {
        0.0
    } else {
        (100.0 * transmit / denom).clamp(0.0, 100.0)
    }
}

/// %c aggregated over a workload from its cache hit rate: each hit rides the front (100% c), each
/// miss recomputes (~0% c), so the workload's %c is its hit rate in percent.
pub fn c_percent_from_hit_rate(hits: u64, total: u64) -> f64 {
    if total == 0 {
        0.0
    } else {
        100.0 * hits as f64 / total as f64
    }
}

/// A cache hit is luminal — the photon — exactly 100% c.
pub const CACHE_HIT_C_PERCENT: f64 = 100.0;

/// A proof-carried %c report for a runtime surface.
#[derive(Clone, Debug)]
pub struct SpeedOfLightReport {
    /// The runtime surface this measures (e.g. "monster-foil", "uring-laminar", "wasm-simd").
    pub surface: String,
    pub hits: u64,
    pub total: u64,
    /// %c = hit-rate aggregate.
    pub percent_c: f64,
    pub theorem_ids: &'static [&'static str],
}

impl SpeedOfLightReport {
    pub fn from_hits(surface: impl Into<String>, hits: u64, total: u64) -> Self {
        Self {
            surface: surface.into(),
            hits,
            total,
            percent_c: c_percent_from_hit_rate(hits, total),
            theorem_ids: &PERCENT_C_THEOREM_IDS,
        }
    }

    /// True iff this surface rides the front (every operation a cache hit / photon).
    pub fn is_luminal(&self) -> bool {
        self.total > 0 && self.hits == self.total
    }

    /// A one-line, emoji-free summary.
    pub fn summary(&self) -> String {
        format!(
            "{}: {:.1}% c  ({}/{} hits{})",
            self.surface,
            self.percent_c,
            self.hits,
            self.total,
            if self.is_luminal() { ", LUMINAL — rides the front" } else { ", subluminal" }
        )
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn cache_hit_is_luminal() {
        // compute == 0 -> 100% c (the photon).
        assert_eq!(c_percent(2.4, 0.0), 100.0);
        assert_eq!(CACHE_HIT_C_PERCENT, 100.0);
    }

    #[test]
    fn recompute_is_subluminal() {
        // any compute drops it strictly below 100% c.
        assert!(c_percent(1.0, 3.0) < 100.0);
        assert_eq!(c_percent(1.0, 3.0), 25.0);
        assert_eq!(c_percent(2.0, 3.0), 40.0); // less compute share, more c
    }

    #[test]
    fn percent_c_is_the_hit_rate() {
        // 60% cache warmth -> 60% c (the bragged number).
        assert_eq!(c_percent_from_hit_rate(60, 100), 60.0);
        let r = SpeedOfLightReport::from_hits("monster-foil", 100, 100);
        assert!(r.is_luminal());
        assert_eq!(r.percent_c, 100.0);
        assert_eq!(r.theorem_ids.len(), 4);
    }
}
